import{_ as i,o as e,c as t,ag as n}from"./chunks/framework.DTiDeF2Q.js";const k=JSON.parse('{"title":"Alias GNU Core Utilities | Dotfiles (ID)","titleTemplate":":title","description":"Alias GNU Core Utilities menyediakan pintasan untuk perintah utilitas inti yang sering digunakan. Semua fungsi dan alias ini adalah pembungkus untuk GNU Core Utilities.","frontmatter":{"title":"Alias GNU Core Utilities | Dotfiles","description":"Alias GNU Core Utilities menyediakan pintasan untuk perintah utilitas inti yang sering digunakan. Semua fungsi dan alias ini adalah pembungkus untuk GNU Core Utilities.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias GNU Core Utilities preview","canonical":"/id/aliases/gnu/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias GNU Core Utilities","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias GNU Core Utilities - Dotfiles (ID)","permalink":"/id/aliases/gnu/","meta":[{"name":"keywords","content":"alias, gnu, coreutils, linux, macos, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias GNU Core Utilities menyediakan pintasan untuk perintah utilitas inti yang sering digunakan."},{"name":"twitter:title","content":"Alias GNU Core Utilities - Dotfiles (ID)"},{"name":"og:title","content":"Alias GNU Core Utilities - Dotfiles (ID)"},{"name":"og:description","content":"Alias GNU Core Utilities menyediakan pintasan untuk perintah utilitas inti yang sering digunakan."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/gnu/index.md","filePath":"id/aliases/gnu/index.md","lastUpdated":1773010926000}'),l={name:"id/aliases/gnu/index.md"};function s(o,a,d,r,u,c){return e(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="alias-gnu" tabindex="-1">Alias GNU <a class="header-anchor" href="#alias-gnu" aria-label="Permalink to &quot;Alias GNU&quot;">​</a></h1><p>Kelola alias GNU. Bagian dari konfigurasi <strong>Universal Dotfiles</strong>.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias ini didefinisikan di <code>gnu.aliases.sh</code> dan dimuat secara otomatis oleh <code>chezmoi</code>.</p><h2 id="alias" tabindex="-1">Alias <a class="header-anchor" href="#alias" aria-label="Permalink to &quot;Alias&quot;">​</a></h2><p>Ini adalah koleksi alias untuk paket GNU Coreutils, satu set utilitas Unix standar yang sering disertakan dalam distribusi Linux. Alias ini memudahkan penggunaan utilitas ini dengan menyediakan perintah singkat yang menggantikan nama utilitas lengkap.</p><h3 id="utilitas-manajemen-file-dasar" tabindex="-1">Utilitas Manajemen File Dasar <a class="header-anchor" href="#utilitas-manajemen-file-dasar" aria-label="Permalink to &quot;Utilitas Manajemen File Dasar&quot;">​</a></h3><ul><li><code>basename</code> Hapus direktori dan sufiks dari nama file.</li><li><code>cp</code> Salin file dan direktori.</li><li><code>dirname</code> Hapus sufiks non-direktori dari nama file.</li><li><code>ln</code> Buat link antar file.</li><li><code>ls</code> Daftar isi direktori.</li><li><code>mkdir</code> Buat direktori.</li><li><code>mv</code> Pindahkan atau ganti nama file atau direktori.</li><li><code>pwd</code> Cetak nama direktori kerja saat ini.</li><li><code>rm</code> Hapus file atau direktori.</li><li><code>rmdir</code> Hapus direktori kosong.</li></ul><h3 id="utilitas-manipulasi-konten-file" tabindex="-1">Utilitas Manipulasi Konten File <a class="header-anchor" href="#utilitas-manipulasi-konten-file" aria-label="Permalink to &quot;Utilitas Manipulasi Konten File&quot;">​</a></h3><ul><li><code>awk</code> Bahasa pemindaian dan pemrosesan pola.</li><li><code>cat</code> Gabungkan dan tampilkan file.</li><li><code>cut</code> Hapus bagian dari setiap baris file.</li><li><code>diff</code> Bandingkan file baris per baris.</li><li><code>grep</code> Cetak baris yang cocok dengan pola.</li><li><code>head</code> Keluarkan bagian pertama file.</li><li><code>sed</code> Stream editor untuk memfilter dan mengubah teks.</li><li><code>sort</code> Urutkan baris file teks.</li><li><code>tail</code> Keluarkan bagian terakhir file.</li><li><code>tr</code> Terjemahkan atau hapus karakter.</li></ul><h3 id="utilitas-checksum-dan-kriptografi-file" tabindex="-1">Utilitas Checksum dan Kriptografi File <a class="header-anchor" href="#utilitas-checksum-dan-kriptografi-file" aria-label="Permalink to &quot;Utilitas Checksum dan Kriptografi File&quot;">​</a></h3><ul><li><code>md5sum</code> Cetak atau periksa message digest MD5.</li><li><code>sha1sum</code> Cetak atau periksa message digest SHA1.</li><li><code>sha256sum</code> Cetak atau periksa message digest SHA256.</li><li><code>sha512sum</code> Cetak atau periksa message digest SHA512.</li></ul><h3 id="utilitas-file-lainnya" tabindex="-1">Utilitas File Lainnya <a class="header-anchor" href="#utilitas-file-lainnya" aria-label="Permalink to &quot;Utilitas File Lainnya&quot;">​</a></h3><ul><li><code>base64</code> Encode atau decode data base64.</li></ul>',14)])])}const g=i(l,[["render",s]]);export{k as __pageData,g as default};
